576→pub async fn parallel_scan(
577→    frontend_config: &FrontendConfig,
578→    analyses: &[FunctionAnalysis],
579→    config: &ScanConfig,
580→) -> Result<ParallelScanResult, ScanError> {
581→    let call_graph = CallGraph::from_analyses(analyses);
582→    let order_entries = call_graph.test_order()?;
583→
584→    // Flatten test order into layers. Each layer contains functions whose
585→    // callees are all in previous layers.
586→    let all_layers = build_layers(&order_entries, &call_graph);
587→
588→    // Apply stratum filter: only explore functions in selected layers.
589→    let layers: Vec<Vec<String>> = if let Some(ref spec) = config.stratum {
590→        let max_layer = if all_layers.is_empty() { 0 } else { all_layers.len() - 1 };
591→        let range = crate::stratum::resolve_range(spec, max_layer)?;
592→        crate::stratum::filter_layers(&all_layers, &range)
593→            .into_iter()
594→            .map(|(_, funcs)| funcs.clone())
595→            .collect()
596→    } else {
597→        all_layers
598→    };
599→
600→    let analysis_map: HashMap<&str, &FunctionAnalysis> =
601→        analyses.iter().map(|a| (a.name.as_str(), a)).collect();
602→
603→    let effective_parallelism = config.parallelism.max(1);
604→    let pool = Arc::new(
605→        WorkerPool::spawn(frontend_config, effective_parallelism)
606→            .await
607→            .map_err(ScanError::Frontend)?,
608→    );
609→
610→    let behavior_maps: Arc<Mutex<HashMap<String, BehaviorMap>>> =
611→        Arc::new(Mutex::new(HashMap::new()));
612→
613→    // Load the interesting input pool for cross-function seed sharing.
614→    let input_pool: Arc<Mutex<InterestingPool>> = {
615→        let loaded = config
616→            .pool_path
617→            .as_ref()
618→            .and_then(|p| interesting_pool::load_pool(p).ok().flatten())
619→            .unwrap_or_default();
620→        Arc::new(Mutex::new(loaded))
621→    };
622→    input_pool.lock().await.epoch += 1;
623→
624→    // Deep fingerprints: accumulated across layers. Since functions within a
625→    // layer have no cross-dependencies, callee deep FPs are always from prior
626→    // layers and this map is immutable during within-layer parallel execution.
627→    let mut deep_fingerprints: HashMap<String, String> = HashMap::new();
628→
629→    // Load checkpoint for resume support.
630→    let scan_id = crate::checkpoint::ScanCheckpoint::compute_scan_id(
631→        &config.file_map.values().map(|s| s.as_str()).collect::<Vec<_>>(),
632→    );
633→    let mut checkpoint = match &config.resume_path {
634→        Some(path) => {
635→            match crate::checkpoint::ScanCheckpoint::load(path) {
636→                Ok(Some(cp)) if cp.scan_id == scan_id => cp,
637→                Ok(Some(_)) => {
638→                    log::info!("checkpoint scan_id mismatch, starting fresh");
639→                    crate::checkpoint::ScanCheckpoint::new(scan_id)
640→                }
641→                Ok(None) => crate::checkpoint::ScanCheckpoint::new(scan_id),
642→                Err(e) => {
643→                    log::warn!("failed to load checkpoint: {e}, starting fresh");
644→                    crate::checkpoint::ScanCheckpoint::new(scan_id)
645→                }
646→            }
647→        }
648→        None => crate::checkpoint::ScanCheckpoint::new(scan_id),
649→    };
650→
651→    let mut all_results: Vec<FunctionResult> = Vec::new();
652→    let mut test_order: Vec<String> = Vec::new();
653→    let mut skipped: Vec<SkippedFunction> = Vec::new();
654→
655→    let scan_start = Instant::now();
656→
657→    for (layer_idx, layer) in layers.iter().enumerate() {
658→        // Check total scan timeout at layer boundary.
659→        if let Some(total) = config.timeout_total
660→            && scan_start.elapsed() >= total
661→        {
662→            // Skip all functions in this and remaining layers.
663→            for remaining_layer in &layers[layer_idx..] {
664→                for func_name in remaining_layer {
665→                    skipped.push(SkippedFunction {
666→                        function_name: func_name.clone(),
667→                        reason: "total scan timeout exceeded".into(),
668→                        category: SkipCategory::Error,
669→                    });
670→                }
671→            }
672→            break;
673→        }
674→
675→        // Build tasks for this layer: each function paired with its mocks.
676→        let mut tasks = Vec::new();
677→        // Track deep FPs computed in this layer (added after the layer completes).
678→        let mut layer_deep_fps: Vec<(String, String)> = Vec::new();
679→
680→        for func_name in layer {
681→            test_order.push(func_name.clone());
682→
683→            let analysis = match analysis_map.get(func_name.as_str()) {
684→                Some(a) => *a,
685→                None => {
686→                    skipped.push(SkippedFunction {
687→                        function_name: func_name.clone(),
688→                        reason: "no analysis found".into(),
689→                        category: SkipCategory::Error,
690→                    });
691→                    continue;
692→                }
693→            };
