695→            // Compute shallow fingerprint, then deep fingerprint incorporating callees.
696→            let shallow_fingerprint =
697→                compute_fingerprint_for_function(func_name, analysis, config);
698→
699→            let callees = call_graph.callees(func_name);
700→            let current_deep_fp = shallow_fingerprint.as_ref().map(|sfp| {
701→                crate::fingerprint::compute_deep_fingerprint(sfp, &deep_fingerprints, &callees)
702→            });
703→
704→            // Check resume checkpoint first (uses deep FP).
705→            if let (Some(cache), Some(dfp)) = (&config.cache, &current_deep_fp)
706→                && checkpoint.is_completed(func_name, dfp, cache)
707→                && let Ok(Some(cached_map)) = cache.load(func_name)
708→            {
709→                let mut maps = behavior_maps.lock().await;
710→                maps.insert(func_name.clone(), cached_map);
711→                drop(maps);
712→                layer_deep_fps.push((func_name.clone(), dfp.clone()));
713→                skipped.push(SkippedFunction {
714→                    function_name: func_name.clone(),
715→                    reason: "resumed from checkpoint".into(),
716→                    category: SkipCategory::Expected,
717→                });
718→                continue;
719→            }
720→
721→            // Check cache freshness using deep fingerprint.
722→            if let (Some(cache), Some(dfp)) = (&config.cache, &current_deep_fp)
723→                && let Ok(true) = cache.is_fresh(func_name, dfp)
724→                && let Ok(Some(cached_map)) = cache.load(func_name)
725→            {
726→                let mut maps = behavior_maps.lock().await;
727→                maps.insert(func_name.clone(), cached_map);
728→                drop(maps);
729→                layer_deep_fps.push((func_name.clone(), dfp.clone()));
730→                skipped.push(SkippedFunction {
731→                    function_name: func_name.clone(),
732→                    reason: "unchanged (fingerprint match)".into(),
733→                    category: SkipCategory::Expected,
734→                });
735→                continue;
736→            }
737→
738→            // Try loading cached behavior maps for callees not yet in memory.
739→            if let Some(ref cache) = config.cache {
740→                let mut maps = behavior_maps.lock().await;
741→                for dep in &analysis.dependencies {
742→                    if !maps.contains_key(&dep.symbol)
743→                        && let Ok(Some(cached)) = cache.load(&dep.symbol)
744→                    {
745→                        maps.insert(dep.symbol.clone(), cached);
746→                    }
747→                }
748→                drop(maps);
749→            }
750→
751→            // Build mocks from callees that have already been tested.
752→            let maps = behavior_maps.lock().await;
753→            let mut mocks: Vec<MockConfig> = Vec::new();
754→            let mut mocks_used: Vec<MockUsage> = Vec::new();
755→            for callee in &callees {
756→                if let Some(bmap) = maps.get(callee) {
757→                    mocks.push(mock_config_from_behavior_map(bmap));
758→                    mocks_used.push(MockUsage {
759→                        name: callee.clone(),
760→                        source: MockSource::CachedBehaviorMap,
761→                    });
762→                }
763→            }
764→            drop(maps);
765→
766→            // Generate auto-mocks for remaining unmocked dependencies.
767→            let auto_mocks = crate::auto_mock::generate_auto_mocks(
768→                &analysis.dependencies,
769→                None,
770→                &config.mock_overrides,
771→                &mocks,
772→            );
773→            for am in &auto_mocks {
774→                mocks_used.push(MockUsage {
775→                    name: am.symbol.clone(),
776→                    source: MockSource::TypeAwareStub,
777→                });
778→            }
779→            mocks.extend(auto_mocks);
780→            mocks_used.sort_by(|a, b| a.name.cmp(&b.name));
781→
782→            let file = config
783→                .file_map
784→                .get(func_name)
785→                .cloned()
786→                .unwrap_or_default();
787→
788→            let pool_seeds = {
789→                let pool_guard = input_pool.lock().await;
790→                crate::input_gen::pool_to_candidate_inputs(&analysis.params, &pool_guard)
791→            };
792→
793→            let candidate_inputs = load_config_candidate_inputs(
794→                func_name,
795→                &config.config_dir,
796→                config.max_iterations_per_function,
797→                config.timeout_per_fn.as_secs(),
798→            );
799→
800→            let explore_config = ExploreConfig {
801→                file,
802→                max_iterations: config.max_iterations_per_function,
803→                seed: config.seed,
804→                mocks,
805→                setup_file: None,
806→                setup_mode: crate::config::SetupMode::PerFunction,
807→                value_sources: vec![],
808→                capabilities: crate::orchestrator::FrontendCapabilities::default(),
809→                user_seeds: vec![],
810→                candidate_inputs,
811→                pool_seeds,
812→                project_root: config.project_root.clone(),
813→                loop_buckets: explorer::LoopBuckets::default(),
814→                timeout_explore: config.timeout_explore,
815→            };
816→
817→            tasks.push((func_name.clone(), analysis.clone(), explore_config, mocks_used, callees, current_deep_fp));
818→        }
819→
820→        // Execute tasks in parallel across the worker pool.
821→        // Each task checks out a worker, explores, then returns the worker.
822→        let mut handles = Vec::new();
823→
824→        let fe_config = Arc::new(frontend_config.clone());
825→
826→        for (func_name, analysis, explore_config, mocks_used, callees, deep_fp) in tasks {
827→            let pool = Arc::clone(&pool);
828→            let behavior_maps = Arc::clone(&behavior_maps);
829→            let input_pool = Arc::clone(&input_pool);
830→            let timeout = config.timeout_per_fn;
831→            let cache = config.cache.clone();
832→            let fe_config = Arc::clone(&fe_config);
833→
834→            let handle = tokio::spawn(async move {
835→                let mut frontend = pool.checkout().await;
836→
837→                let result = tokio::time::timeout(
838→                    timeout,
839→                    explore_single_function(
840→                        &mut frontend,
841→                        &func_name,
842→                        &analysis,
843→                        &explore_config,
844→                        &mocks_used,
845→                        &callees,
846→                        &behavior_maps,
847→                        deep_fp.clone(),
848→                        &input_pool,
849→                    ),
